elements.expression:
shape "square" fill="#00AADE" border="rgba(255,255,255,0)" borderWidth=0 maintainAspect=false
| render css=".canvasRenderEl{

}
" containerStyle={containerStyle borderRadius="10px"}

filters
| essql "SELECT COUNT(size) AS EINS FROM queues"
| metric "Throughput" 
  metricFont={font family="'Open Sans', Helvetica, Arial, sans-serif" size=24 align="center" weight="normal" underline=false italic=false color="#FFFFFF"} 
  labelFont={font family="'Open Sans', Helvetica, Arial, sans-serif" size=14 align="center" weight="normal" underline=false italic=false color="#FFFFFF"} metricFormat="0,0.[000]"
| render 
  css=".canvasRenderEl{
 background-color: green;
 border-radius: 10px;
 padding-top:10px;
}"

filters
| esdocs query="" index="queues" fields="size"
